SELECT DISTINCT brands.brand_name
FROM brands
JOIN weaknesses ON brands.brand_id = weaknesses.brand_id;

SELECT t.trend_name, t.trend_description
FROM market_trends t
INNER JOIN competitors c ON t.trend_description LIKE '%' || c.competitor_name || '%';

SELECT strength, source 
FROM strengths 
WHERE brand_id = (SELECT brand_id FROM brands WHERE brand_name = 'Trello');

SELECT competitor_name, competitor_description
FROM competitors
WHERE brand_id = 1;

SELECT DISTINCT b.brand_id, b.brand_name
FROM brands b
JOIN strengths s ON b.brand_id = s.brand_id;
